package docgen

func renderHeadAssets() string {
	return `<link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@400;500&family=IBM+Plex+Sans:wght@400;500;600;700&family=Source+Serif+4:wght@500;600&display=swap" rel="stylesheet"><script type="module">import mermaid from 'https://cdn.jsdelivr.net/npm/mermaid@11/dist/mermaid.esm.min.mjs';mermaid.initialize({startOnLoad:true,theme:'base',themeVariables:{primaryColor:'#CFE7D8',lineColor:'#245841',fontFamily:'IBM Plex Sans'}});</script><style>:root{--bg:#f6f3ea;--panel:#fffdf8;--text:#1e2a24;--muted:#5d6b63;--accent:#245841;--line:#d8d4c8;--note:#eef6f1}*{box-sizing:border-box}html,body{margin:0;padding:0;background:radial-gradient(circle at 0% 0%,#fdf7ee 0,#f6f3ea 42%,#f2efe6 100%);color:var(--text)}body{font-family:'IBM Plex Sans',sans-serif}h1,h2,h3{font-family:'Source Serif 4',serif;margin:0 0 .6rem}a{color:var(--accent);text-decoration:none}.page{display:grid;grid-template-columns:280px minmax(0,1fr);min-height:100vh}.sidebar{position:sticky;top:0;height:100vh;border-right:1px solid var(--line);padding:1.25rem;background:linear-gradient(180deg,#f2f7f2,#f8f5ee)}.brand{font-size:1.08rem;font-weight:700;margin-bottom:.5rem}.caption{color:var(--muted);font-size:.92rem;margin-bottom:1rem}.toc a{display:block;padding:.4rem 0;color:#2d4c3f}.content{padding:1.5rem;max-width:1060px}.hero{background:var(--panel);border:1px solid var(--line);border-radius:16px;padding:1.1rem 1.2rem;margin-bottom:1rem}.meta{color:var(--muted);margin-top:.35rem}.cards{display:grid;gap:.75rem;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));margin:1rem 0}.card{background:var(--panel);border:1px solid var(--line);border-radius:14px;padding:.75rem}.k{font-size:.82rem;color:var(--muted)}.v{font-size:1.3rem;font-weight:700;margin-top:.1rem}section{margin:1rem 0;background:var(--panel);border:1px solid var(--line);border-radius:16px;padding:1rem}pre{white-space:pre-wrap;word-break:break-word;background:#fff;border:1px solid var(--line);border-radius:10px;padding:.75rem;overflow:auto;font-family:'IBM Plex Mono',monospace}table{border-collapse:collapse;width:100%}th,td{border:1px solid var(--line);padding:.45rem .5rem;text-align:left}th{background:#f4f7f5}.mermaid-wrap{background:var(--note);border:1px solid #d3e4da;border-radius:10px;padding:.6rem}.code-note{background:#f8f8f4;border-left:4px solid #c5d9cd;padding:.6rem .7rem;border-radius:8px}.pill{display:inline-block;background:#e2efe7;border:1px solid #c7dfd1;border-radius:999px;padding:.15rem .5rem;font-size:.82rem;margin-right:.4rem}.list li{margin:.32rem 0}.sample{margin:.7rem 0}.sample-title{font-weight:600;margin-bottom:.3rem}@media (max-width:920px){.page{display:block}.sidebar{position:static;height:auto;border-right:none;border-bottom:1px solid var(--line)}.content{padding:1rem}}</style>`
}
